-- Table structure for print_history
-- ----------------------------
DROP TABLE IF EXISTS `print_history`;
CREATE TABLE `print_history`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '打印履历ID',
  `report_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '报告类型（shipping_report等）',
  `report_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '报告标题',
  `user_id` int NULL DEFAULT NULL COMMENT '打印用户ID',
  `user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '打印用户名',
  `printed_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `print_date` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '打印日期时间',
  `filters` json NULL COMMENT '打印时使用的筛选条件',
  `record_count` int NULL DEFAULT 0 COMMENT '打印记录数量',
  `status` enum('成功','失败','取消') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '成功' COMMENT '打印状态',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '错误信息（如果有）',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_report_type`(`report_type` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_print_date`(`print_date` ASC) USING BTREE,
  INDEX `idx_printed_at`(`printed_at` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2015 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '打印履历表' ROW_FORMAT = DYNAMIC;

